const input = $input.first();
const body = input.json.body || input.json || {};
const binary = input.binary || {};

function firstValue(value) {
  if (Array.isArray(value)) return value[0] ?? '';
  return value ?? '';
}

function cleanText(value, maxLen) {
  const raw = String(firstValue(value))
    .replace(/[\x00-\x1F\x7F]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  return raw.slice(0, maxLen);
}

function whereValue(value) {
  return String(value || '')
    .replace(/[(),~]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const name = cleanText(body.name, 80);
const mallId = cleanText(body.mallId, 100);
const phoneDigits = String(firstValue(body.phone)).replace(/\D/g, '');
const phone = phoneDigits.length === 11
  ? phoneDigits.slice(0, 3) + '-' + phoneDigits.slice(3, 7) + '-' + phoneDigits.slice(7)
  : cleanText(body.phone, 20);
const email = cleanText(body.email, 120);
const association = cleanText(body.association, 120);
const recordId = cleanText(body.recordId, 40);
const submitModeRaw = cleanText(body.submitMode, 20).toLowerCase();
const submitMode = submitModeRaw === 'update'
  ? 'update'
  : (submitModeRaw === 'create-new' || submitModeRaw === 'createnew' ? 'create-new' : 'auto');

const errors = [];
if (!name) errors.push('성함을 입력해주세요.');
if (!/^010\d{8}$/.test(phoneDigits)) errors.push('연락처는 010으로 시작하는 11자리 번호여야 합니다.');
if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) errors.push('올바른 이메일 형식을 입력해주세요.');

const duplicateParts = [];
const safeMallId = whereValue(mallId);
const safePhone = whereValue(phone);
const safePhoneRaw = whereValue(phoneDigits);
const safeEmail = whereValue(email);
const safeRecordId = whereValue(recordId);

if (safeRecordId) duplicateParts.push('(Id,eq,' + safeRecordId + ')');
if (safeMallId) duplicateParts.push('(자사몰 ID,eq,' + safeMallId + ')');
if (safePhone) duplicateParts.push('(연락처,like,%' + safePhone + '%)');
if (safePhoneRaw) duplicateParts.push('(연락처,like,%' + safePhoneRaw + '%)');
if (safeEmail) duplicateParts.push('(이메일 주소,eq,' + safeEmail + ')');

const fileKeys = Object.keys(binary).sort();
const now = new Date();
const kst = new Date(now.getTime() + (9 * 60 * 60 * 1000));
const applyDate = kst.toISOString().slice(0, 10);

if (errors.length > 0) {
  return [{
    json: {
      _valid: false,
      _response: {
        ok: false,
        code: 'INVALID_INPUT',
        message: errors[0],
        errors,
      },
    },
  }];
}

return [{
  json: {
    _valid: true,
    name,
    mallId,
    phone,
    phoneRaw: phoneDigits,
    email,
    association,
    recordId,
    submitMode,
    duplicateWhere: duplicateParts.join('~or'),
    fileKeys,
    applyDate,
  },
  binary,
}];

const response = $input.first().json;
const form = $('Code: 입력 검증').first();
const list = Array.isArray(response.list) ? response.list : [];
const submitMode = form.json.submitMode;

function normalizeDigits(value) {
  return String(value || '').replace(/[^0-9]/g, '');
}

function normalizeText(value) {
  return String(value || '').trim().toLowerCase();
}

function firstNonEmpty(values) {
  for (const value of values) {
    const text = String(value || '').trim();
    if (text) return text;
  }
  return '';
}

function normalizeAttachmentValue(value) {
  if (!value) return [];
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') {
    const text = value.trim();
    if (!text) return [];
    try {
      const parsed = JSON.parse(text);
      return normalizeAttachmentValue(parsed);
    } catch {
      return text.split(/[\n,]/).map(function(part) {
        return part.trim();
      }).filter(Boolean);
    }
  }
  if (typeof value === 'object') {
    if (Array.isArray(value.data)) return value.data;
    if (Array.isArray(value.files)) return value.files;
    return Object.keys(value).length > 0 ? [value] : [];
  }
  return [];
}

function countAttachments(record) {
  return normalizeAttachmentValue(record && record['증빙서류 첨부']).length;
}

function buildApplicationSummary(record) {
  if (!record) return null;
  const status = String(record['진행 상태'] || '').trim();
  const rejectReason = String(record['반려 사유'] || '').trim();
  return {
    recordId: String(record.Id || record.id || ''),
    name: String(record['성함'] || '').trim(),
    mallId: String(record['자사몰 ID'] || '').trim(),
    phone: String(record['연락처'] || '').trim(),
    email: String(record['이메일 주소'] || '').trim(),
    association: String(record['소속 협회'] || '').trim(),
    status,
    rejectReason,
    isRejected: status === '반려',
    isApproved: status === '승인완료',
    isPending: !status || status === '승인대기' || status === '수동처리필요',
    submittedAt: firstNonEmpty([record['신청 일시'], record.CreatedAt, record.createdAt]),
    updatedAt: firstNonEmpty([record.UpdatedAt, record.updatedAt]),
    attachmentCount: countAttachments(record),
  };
}

function findExistingRecord() {
  const requestedId = String(form.json.recordId || '').trim();
  if (requestedId) {
    const byId = list.find(function(record) {
      return String(record.Id || record.id || '') === requestedId;
    });
    return byId || null;
  }

  const mallId = normalizeText(form.json.mallId);
  if (mallId) {
    const byMallId = list.find(function(record) {
      return normalizeText(record['자사몰 ID']) === mallId;
    });
    if (byMallId) return byMallId;
  }

  const phoneDigits = normalizeDigits(form.json.phoneRaw || form.json.phone);
  if (phoneDigits) {
    const byPhone = list.find(function(record) {
      return normalizeDigits(record['연락처']) === phoneDigits;
    });
    if (byPhone) return byPhone;
  }

  const email = normalizeText(form.json.email);
  if (email) {
    const byEmail = list.find(function(record) {
      return normalizeText(record['이메일 주소']) === email;
    });
    if (byEmail) return byEmail;
  }

  return list[0] || null;
}

const existing = findExistingRecord();
const existingApplication = buildApplicationSummary(existing);
const existingAttachments = normalizeAttachmentValue(existing && existing['증빙서류 첨부']);
const existingId = existingApplication ? existingApplication.recordId : '';
const existingStatus = existingApplication ? existingApplication.status : '';

if (existing && (submitMode === 'auto' || submitMode === 'create-new')) {
  return [{
    json: {
      _continue: false,
      _response: {
        ok: false,
        code: 'DUPLICATE_APPLICATION',
        message: '이미 신청하셨어요. 새로 다시 신청하지 않아도 됩니다. 기존 신청만 수정·보완할 수 있습니다.',
        recordId: existingId,
        existingStatus,
        existingApplication,
      },
    },
    binary: form.binary,
  }];
}

const targetRecordId = existingId || form.json.recordId;
if (submitMode === 'update' && !existing) {
  return [{
    json: {
      _continue: false,
      _response: {
        ok: false,
        code: 'MISSING_RECORD_ID',
        message: '수정할 기존 신청 정보를 찾지 못했습니다. 연락처를 다시 입력해 기존 신청을 조회한 뒤 수정·보완해 주세요.',
      },
    },
    binary: form.binary,
  }];
}

const isUpdate = submitMode === 'update';
const isApprovedRecord = existingStatus === '승인완료';

return [{
  json: {
    _continue: true,
    isUpdate,
    targetRecordId,
    existingStatus,
    existingAttachments,
    existingAttachmentCount: existingAttachments.length,
    shouldResetReviewState: isUpdate && !isApprovedRecord,
    name: form.json.name,
    mallId: form.json.mallId,
    phone: form.json.phone,
    phoneRaw: form.json.phoneRaw,
    email: form.json.email,
    association: form.json.association,
    fileKeys: form.json.fileKeys,
    applyDate: form.json.applyDate,
  },
  binary: form.binary,
}];

const source = $input.first();
return (source.json.fileKeys || []).map((key) => ({
  json: {
    targetRecordId: source.json.targetRecordId,
  },
  binary: {
    uploadFile: source.binary[key],
  },
}));

const base = $('Code: 중복 처리 결정').first().json;
const attachments = [];
for (const item of $input.all()) {
  if (Array.isArray(item.json)) {
    attachments.push(...item.json);
  } else if (item.json && Array.isArray(item.json.data)) {
    attachments.push(...item.json.data);
  } else if (item.json && Object.keys(item.json).length > 0) {
    attachments.push(item.json);
  }
}
return [{
  json: {
    ...base,
    attachments,
  },
}];

const base = $('Code: 중복 처리 결정').first().json;
return [{
  json: {
    ...base,
    attachments: [],
  },
}];

const item = $input.first().json;

function normalizeAttachmentValue(value) {
  if (!value) return [];
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') {
    const text = value.trim();
    if (!text) return [];
    try {
      const parsed = JSON.parse(text);
      return normalizeAttachmentValue(parsed);
    } catch {
      return text.split(/[\n,]/).map(function(part) {
        return part.trim();
      }).filter(Boolean);
    }
  }
  if (typeof value === 'object') {
    if (Array.isArray(value.data)) return value.data;
    if (Array.isArray(value.files)) return value.files;
    return Object.keys(value).length > 0 ? [value] : [];
  }
  return [];
}

const newAttachments = normalizeAttachmentValue(item.attachments);
const existingAttachments = normalizeAttachmentValue(item.existingAttachments);
const recordPayload = {
  '성함': item.name,
  '자사몰 ID': item.mallId,
  '연락처': item.phone,
  '신청 일시': item.applyDate,
};
if (item.email) recordPayload['이메일 주소'] = item.email;
if (item.association) recordPayload['소속 협회'] = item.association;
if (newAttachments.length > 0) {
  recordPayload['증빙서류 첨부'] = item.isUpdate
    ? existingAttachments.concat(newAttachments)
    : newAttachments;
}

if (item.shouldResetReviewState) {
  recordPayload['진행 상태'] = null;
  recordPayload['n8n_처리완료'] = 0;
  recordPayload['n8n_처리일시'] = null;
  recordPayload['n8n_신청알림'] = 0;
  recordPayload['n8n_반려알림'] = 0;
  recordPayload['n8n_반려_retry'] = 0;
  recordPayload['반려 사유'] = '';
}

return [{
  json: {
    ...item,
    recordPayload,
  },
}];

const base = $('Code: 레코드 페이로드 생성').first().json;
const result = $input.first().json;

function parseJsonText(value) {
  if (typeof value !== 'string' || !value.trim()) return null;
  try {
    return JSON.parse(value);
  } catch {
    return null;
  }
}

function extractBufferedPayload(payload) {
  const buffered = payload && payload._readableState && Array.isArray(payload._readableState.buffer)
    ? payload._readableState.buffer
    : [];

  for (const chunk of buffered) {
    if (!chunk) continue;
    if (typeof chunk === 'string') {
      const parsed = parseJsonText(chunk);
      if (parsed) return parsed;
      continue;
    }
    if (Array.isArray(chunk.data)) {
      const parsed = parseJsonText(Buffer.from(chunk.data).toString('utf8'));
      if (parsed) return parsed;
    }
  }

  return null;
}

function extractRecordId(payload) {
  if (!payload) return '';
  if (typeof payload === 'string') {
    const parsed = parseJsonText(payload);
    return parsed ? extractRecordId(parsed) : '';
  }
  if (Array.isArray(payload)) {
    for (const item of payload) {
      const id = extractRecordId(item);
      if (id) return id;
    }
    return '';
  }
  if (payload.Id || payload.id) return String(payload.Id || payload.id);
  if (payload.data) {
    const id = extractRecordId(payload.data);
    if (id) return id;
  }
  if (payload.list) {
    const id = extractRecordId(payload.list);
    if (id) return id;
  }
  if (payload.body) {
    const id = extractRecordId(payload.body);
    if (id) return id;
  }
  const bufferedPayload = extractBufferedPayload(payload);
  return bufferedPayload ? extractRecordId(bufferedPayload) : '';
}

const recordId = extractRecordId(result) || String(base.targetRecordId || '');
return [{
  json: {
    ok: true,
    mode: base.isUpdate ? 'updated' : 'created',
    recordId,
    message: base.isUpdate ? '기존 신청을 수정했습니다.' : '신청이 완료되었습니다.',
  },
}];
